        <div class="favorito-box" @click="favoritoGame">
           <n-icon :component="Heart32Regular" v-if="!gameInfo.favorite"></n-icon><n-icon :component="Heart48Filled" color="rgb(255, 71, 87)" v-else ></n-icon> {{ randomNumber }}
        </div>
    </div> -->

    <div  :class="isThird?'game-warp':''" :style="isThird?judgeIframeStyle():{}">
            <template v-if="!gameInfo.self">
                <!-- <Teleport :to="toTarget" > -->
                    
                    <thirdGameTop v-model:isScreen="isScreen" :gameInfo="gameInfo" @updateFavorite="updateFavoriteStatus" v-if="!configStore.isMobile" />
                    <div  :class="isScreen ? 'full-screen-content' :'third-game-content'">
                        <iframe v-if="isHtml == 1" :srcdoc="gameSrc" frameborder="0" pointerEvents="none"  :class="configStore.isMobile ? 'iframe-style' : 'pc-iframe-style'"></iframe>
                        <iframe v-else :src="gameSrc" frameborder="0" pointerEvents="none" :class="configStore.isMobile ? 'iframe-style':'pc-iframe-style'"></iframe>
                        <draggable v-if="configStore.isMobile && isShow"></draggable>
                        <div class="content" @click="isScreen = false" v-if="isScreen == true">
                            <img :src="$formatOnlineImg(`/common/exit_full_screen.png`)" />
                        </div>
                    </div>
                    
                <!-- </Teleport> -->
            </template>
            <template v-else>
                <div v-if="selfGameSrc !=''" :class="isScreen ? 'full-screen-content' :'third-game-content'">
                    <iframe :src="gameSrcWithParams" frameborder="0" pointerEvents="none" :class="configStore.isMobile ? 'iframe-style':'pc-iframe-style'"></iframe>
                </div>
                <div v-else>
                    <GameCanvas ref="gameCanvasRef" :gameInfo="gameInfo"/>
                </div>
            </template>
    </div>
    <div class="game-list-wrapper" v-if="!gameInfo.self && !configStore.isMobile">
        <div class="game-header" >
            <div class="left">
                <div class="category-name">{{ $t('gameList.recommendGames') }}</div>
            </div>    
        </div> 
        <div class="game-content-wrapper"  v-if="gameArrList.length>0">
            <n-grid :x-gap="xGap"  cols="3 768:6">
                <n-grid-item v-for="(item, index) in gameArrList">
                    <GameItem :gameInfo="item" />
                </n-grid-item>
            </n-grid>
        </div>
        <div class="empty-img" v-else >
            <img :src="$formatOnlineImg(`/empty.png`)" />
            <div class="data">NO DATA</div>
        </div>
    </div>
    <!-- <div v-else class="game-img">
        <n-image  height="400"  :src="gameInfo.self?$formatOnlineImg(gameInfo.icon): $formatOnlineCommonImg(gameInfo.icon)" preview-disabled	/>
        <div class="img-cover">
            <div class="img-button">
                <n-space>
                    <div class="start-button" @click="hanldeClickBegin(false)">{{$t('game.start')}}</div>
                    <div class="start-button" @click="hanldeClickBegin(true)" v-if="gameInfo.demo">{{$t('game.demo')}}</div>
                </n-space>
            </div>
        </div>
    </div> -->

</template>
<script setup name="gameIndex">
import {UserOutlined} from "@vicons/antd"
import GameCanvas from './components/GameCanvas.vue'
import { useUserStore } from "piniaModules/user"
import { getGameInfo ,getGameLink,favorite,unFavorite,randHotList} from '@/api/game'
import { Heart32Regular,Heart48Filled,FullScreenMaximize24Filled,FullScreenMinimize24Filled } from '@vicons/fluent'
import { useConfigStore } from '@/pinia/modules/config'
import { useI18n } from 'vue-i18n'
import draggable from "@/components/Draggable.vue";
import thirdGameTop from './components/ThirdGameTop.vue';
import { useGameHook } from '@/hooks/useGame.js';
const { judgeGameRouter } = useGameHook()

const { t, locale } = useI18n()
const configStore = useConfigStore()
const randomNumber = ref(Math.floor(Math.random() * (2000 - 1000 + 1)) + 1000);
const playNum = ref(Math.floor(Math.random() * (1000 - 500 + 1)) + 500);
const isScreen = ref(false)
const route = useRoute()
const router = useRouter()
const userStore = useUserStore()
const gameSrc = ref()
const showGame = ref(false)
const gameInfo = ref({})
const gameCanvasRef = ref()
const toTarget = ref('body')
const isThird = ref(false)
const isHtml = ref(0)
const demo = ref(false)
const isShow = ref(false)

// 自研游戏参数
const queryParams = ref({});
const selfGameSrc = ref('')

// 自研游戏cocos拼接参数
const gameSrcWithParams = computed(() => {
    const url = new URL(selfGameSrc.value);
    Object.keys(queryParams.value).forEach(key => {
        url.searchParams.append(key, queryParams.value[key]);
    });
    return url.toString();
});

const hanldeClickBegin = (demo=false)=>{
    if(gameInfo.value.self == 1){
        showGame.value = true
        window.scrollTo(0,0)
        queryParams.value = {
            Domain: location.hostname,
            DistinctId: window.ta?.getDistinctId() ?? "",
            gameToken: userStore.gameToken,
            gameId: gameInfo.value.gameId,
        }
        // if (gameInfo.value.gameId == '449466288872493056')
        //     selfGameSrc.value = "http://192.168.124.88:8089/dice/"
        // else if (gameInfo.value.gameId == '422274078335180800'){
        //     selfGameSrc.value = "http://192.168.124.88:8089/mines/"
        // }
        // else if (gameInfo.value.gameId == '449466288872594730'){
        //     selfGameSrc.value = "http://192.168.124.88:8089/tower/"
        // }
        // else if (gameInfo.value.gameId == '449466288868298753'){
        //     selfGameSrc.value = "http://192.168.124.88:8089/limbo/"
        // }
        // else if (gameInfo.value.gameId == '570453597523939328'){
        //     selfGameSrc.value = "http://192.168.124.88:8089/plinko/"
        // }
        // else if (gameInfo.value.gameId == '449466288872594731'){
        //     selfGameSrc.value = "http://192.168.124.88:8089/ball/"
        // }
        // else {
            setTimeout(() => {
                gameCanvasRef.value.initGameCanvas().then(()=>{
                    console.log('gameCanvasRef.value.initGameCanvas')
                })
            }, 10);
        // }
    }else {
        if(userStore.userInfo.amount/1000 <= 0){
            // configStore.showBalanceModal = true
            router.push({ name: 'home' })
            return
        }
        getGameLink({
            thirdId:gameInfo.value.thirdId,
            platformId:gameInfo.value.platformId,
            gameToken:userStore.gameToken,
            demo:demo,
            mobile:configStore.isMobile
        }).then((res)=>{
            isHtml.value = res.isHtml
            // 0-原始 1-转译 2-自营
            if(res.isHtml == 1) {
                gameSrc.value = atob(res.link)
            } else if (res.isHtml == 2) {
                gameSrc.value = res.link + `&language=${locale.value}`
            }else {
                gameSrc.value = res.link
            }
            showGame.value = true
            
        })
    }
}
const InitGameInfo = (gameId) =>{
    // getGameInfo({gameId}).then((res)=>{
    //     gameInfo.value = res
    //     isShow.value = true
    //     if (!userStore.isLogin && !res.self) {
    //         router.push({ name: 'home' })
    //         configStore.setLoginInfo()
    //         return 
    //     }
    //     if(!res.self){
    //         if (userStore.isLogin) {
    //             timer = setInterval(() => {
    //                 userStore.GetUserInfo() 
    //             }, 10000);
    //         }
    //         isThird.value = true
    //     }
    //     hanldeClickBegin(demo.value)
    // })
    
    gameInfo.value = {gameId: gameId, self: 1}
        isShow.value = true
        hanldeClickBegin(demo.value)

}

const judgeIframeStyle = ()=>{
    if(/Safari/.test(navigator.userAgent) && !/Chrome/.test(navigator.userAgent)){
        return {height:`calc(100vh - 122px)`} 
    } else {
        // return {height:`calc(100vh - 42px)`}
    }
}

let timer = null
const gameArrList = ref([])
const xGap = ref(24)	

const getHotGameList = (gameId)=>{
    return;
    randHotList({gameId}).then(res=>{
        gameArrList.value = res
    })
}
const updateFavoriteStatus = ()=>{
    gameInfo.value.favorite = !gameInfo.value.favorite
}

// 监听vue页面传来的message事件
// 返回主页
window.addEventListener("message", (event) => {
    const data = event.data
    if (data.name === 'gameQuit') {
        router.push('/')
    }
    else if (data.name === 'gameRecharge') {
        configStore.showBalanceModal = true
    }
}, false);

onMounted(() => {

   // const {gameId} = route.query
   // crash
   // const gameId = "441868677966594500";
   // 飞机
   const gameId = "441868677966594500";
   // ball
   // const gameId = "449466288872594731";
   // rouDouble
   // const gameId = "449466288868298752";
   // double
   // const gameId = "449466288872493057";
   // fruitBomb
   // const gameId = "570584962693206016";
   // stairs
   // const gameId = "449466288872594732";
   demo.value = false//route.query.demo
   // InitGameInfo(gameId)
   // getHotGameList(gameId)
   // nextTick(() => {
   //      toTarget.value = configStore.isMobile ? 'body':'.main-content-wrapper'
   // })
    // k3
    // judgeGameRouter("578517046690713600");
    // wingo
    // judgeGameRouter("584206116985114624");
    // 5d
    judgeGameRouter("584205597755445248");
    return ;
   InitGameInfo(gameId)
   getHotGameList(gameId)
   nextTick(() => {
        toTarget.value = configStore.isMobile ? 'body':'.main-content-wrapper'
   })

})
onUnmounted(()=>{
    isThird.value = false
    timer && clearInterval(timer)
})
</script>
<style lang="scss" scoped>
.iframe-style{
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    border: none;
    margin: 0;
    padding: 0;
    overflow: hidden;
    z-index: 1000;
}
.full-screen-content{
    .pc-iframe-style{
        height: 100%;
        left: 0;
        position: fixed;
        top: 0;
        width: 100%;
        z-index: 10000;
    }
}

.game-img{
    display: flex;
    justify-content: center;
    border-radius: 14px;
    margin: 0 auto;
    max-width: 430px;
    overflow: hidden;
    position: relative;
    width: 100%;
    .img-cover{
        background: linear-gradient(0deg,rgba(0,0,0,.8),transparent);
        bottom: 0;
        content: " ";
        left: 0;
        position: absolute;
        right: 0;
        top: 0;
        z-index: 1;
    }
}
.img-button{
    bottom: 30px;
    left: 0;
