    position: relative;
    width: 100%;
    .pc-iframe-style{
        width: 100%;
        height: 100%;
        padding: 12px 0;
        position: absolute;
        z-index:990;
    }
}
.third-game-top{
    display: flex;
    justify-content: space-between;
    .game-top-item{
        display: flex;
        div{
            border-radius:6px;
            background:#343434;
            padding: 7px 15px;
            font-size:14px;
            color:#FFF;
            display: flex;
            align-items:center;
        }
    }
}
.favor-count{
    margin-left:6px;
    cursor: pointer;
}
.game-screen{
    padding:7px !important;
    margin-left:12px;
    cursor: pointer;
}
@media screen and (min-width: 768px){

.game-list-wrapper{
    padding: 30px 0px;
    .game-header{
        margin-bottom:28px;
        .right{
            font-size: 12px;
            font-weight: 400;
            line-height: 14px;
            letter-spacing: 1px;
        }
        img{
            width: 50px;
            height: 50px;
            margin-right:6px;
        }
        .category-name{
            height: 26px;
            font-size: 22px;
            line-height: 26px;
            // letter-spacing: 3.14px;
            color:#FFF0BB;
        }
    }
    .game-content-wrapper{
        .game-tips{
            margin:28px 0 0;
            text-align:center;
            .tips{
                color: rgba(255,255,255,0.4);
                text-align:center;
            }
            div{
                height: 15px;
                font-size: 13px;
                font-weight: 400;
                color: rgba(255,255,255,0.4);
                line-height: 15px;
                text-align:center;
            }
            .more{
                display:flex;
                position:relative;
                align-items:center;
                justify-content:center;
                color:#FFF0BB;
                height: 14px;
                font-size: 12px;
                font-weight: 500;
                line-height: 14px;
                letter-spacing: 0.87px;
                font-family: "Inter-Medium";
                img{
                    height:9px;
                    width:9px;
                    margin:0 5px;
                }
            }
        }
    }
    .empty-img{
        display:block;
        text-align:center;
        margin-bottom:0px;
        margin-top:46px;
        &.like{
            margin-bottom:50px;
            margin-top:110px;
        }
        .data{
            height: 16px;
            font-size: 14px;
            line-height: 16px;
        }
    }
    .end{
        margin-bottom:44px;
    }
}
.content {
    position:fixed;
    right:30px;
    top:30px;
    z-index:10001;
    border-radius: 6px;
    display: flex;
    align-items: center;
    cursor:pointer;
        img{
