<template>
     <div
    class="floating-box"
    :style="{ left: `${position.x}px`, top: `${position.y}px` }"
    @touchstart="startDrag"
    @touchmove="handleTouchMove"
    @touchend="handleTouchEnd"
    ref="floatingBox"
  >
    <div class="content" @click="goHome">
      <div><img :src="$formatOnlineImg(`/home.png`,true)" /></div>
    </div>
  </div>
</template>
<script setup name="DraggableComponents">
import { useRouter } from 'vue-router';
 const position = ref({ x: 16, y: 40 });
 let isDragging = false;
 const router = useRouter();
 const floatingBox = ref()
 let touchStartX = 0;
 let touchStartY = 0;
 let startX = 0;
 let startY = 0;
const touchMoveThreshold = 5; // 阈值，表示移动超过该值才认为是滑动操作
const isVisible = ref(true);
 const startDrag = (event) => {
    //   event.preventDefault();

    const touch = event.touches[0];
    startX = touch.clientX - position.value.x;
    startY = touch.clientY - position.value.y;

    isDragging = true;
};
const handleTouchMove = (event) => {
    if (event.touches.length === 1) {
      const touchMoveX = event.touches[0].clientX - touchStartX;
      const touchMoveY = event.touches[0].clientY - touchStartY;
      const touch = event.touches[0];
        position.value.x = touch.clientX - startX;
        position.value.y = touch.clientY - startY;
        isDragging = false
    // 判断是否是滑动操作
    if (Math.abs(touchMoveX) > touchMoveThreshold || Math.abs(touchMoveY) > touchMoveThreshold) {
        // 是滑动操作，阻止默认行为
          event.preventDefault();
      }
    }
};

const handleTouchEnd = () => {
    // 清空触摸起始坐标
    touchStartX = 0;
    touchStartY = 0;
    checkAutoSnap();
};
const checkAutoSnap = () => {
    // 根据实际需求调整这里的逻辑，比如判断是否离开屏幕边缘
    if (!isDragging) {
    // 移动到屏幕的某个边缘
    const windowWidth = window.innerWidth;
    const windowHeight = window.innerHeight;
    
    if (position.value.x + windowWidth / 2 < windowWidth / 2) {
        position.value.x = 0;
    } else {
        position.value.x = windowWidth -25;
    }
    isDragging = true;
    // if (position.value.y + windowHeight / 2 < windowHeight / 2) {
    //   position.value.y = 0;
    // } else {
    //   position.value.y = "100px";
    // }
    }
};
const goHome = ()=>{
    if(window.getComputedStyle(floatingBox.value).left  ==  (window.innerWidth - 25)+'px'){
        position.value.x = window.innerWidth - 50
    }else{
        router.push({ name: 'home' });
    }
}
</script>
<style lang="scss" scoped>
.floating-box {
  position: fixed;
  z-index: 1001;
  cursor: move;
  // transition: left 0.1s, top 0.1s;
}

.content {
  // padding: 10px;
  img{
    width:40px;
    height:40px;
  }
}
</style>