<template>
    <div class="game-item-wrapper">
        <div class="img-box cursor-pointer"   @click="goGame(gameInfo)">
            <img :src="$formatOnlineImg(`/home/game_wrapper.png`,true)" class="img-box-style" />
            <img :src="defaultImg"  :lazy="true"  class="img-style" :class="[isError? 'loading-img':'']" @error="handleError" @load="handleImageLoad" :alt="gameInfo.name" />
            <img :src="$formatOnlineCommonImg(configStore.baseConfig.gameImageUrl)"  :lazy="true"  class="img-style loading-img"  style="z-index:1" v-if="showLodaing"/>
            <div class="img-hover" v-if="!configStore.isMobile">
                <img   :src="$formatOnlineImg(`/home/gameStart.png`)" > 
                <div class="demo-button"  :style="{backgroundImage:`url(${$formatOnlineImg(`/home/demo_button.png`)})`}" @click.stop="goGame(gameInfo,true)" v-if="gameInfo.damo == 1">Demo</div>
            </div> 
            <div class="img-hover img-like">
                <img :src="$formatOnlineImg(`/home/like.png`,true)" class="like-img" v-if="userFavoriteList.includes(gameInfo.id.toString())">
                <img :src="$formatOnlineImg(`/home/unlike.png`,true)" class="like-img" v-else>
                <div class="like-img-click-container">
                    <span class="like-img-click" @click.stop.self="favoritoGame()"></span>
                </div> 
            </div>
        </div>    
        <div class="name" :style="{backgroundImage:`url(${$formatOnlineImg(`/home/game_name.png`,true)})`}">
            <span class="game-name">{{gameInfo.name}}</span>
        </div>
    </div>
</template>
<script setup name="GameItemComponent">
import { defineProps } from 'vue'
import { useUserStore } from "piniaModules/user"
import { useConfigStore } from '@/pinia/modules/config'
import { useGameHook } from '@/hooks/useGame.js';
import * as gameApi from "@/api/game.js"
import { useI18n } from 'vue-i18n'
const { t  } = useI18n()
const configStore = useConfigStore()
const userStore = useUserStore()
const { judgeGameRouter } = useGameHook()
const props = defineProps({
    gameInfo:{
        type:Object,
        default:()=>{}
    }
})
const isError = ref(false)
const showLodaing = ref(true)
const defaultImg = ref($utilsArr.formatOnlineCommonImg(props.gameInfo.icon))
const router = useRouter()
const goGame = (item,demo=false) => {
     judgeGameRouter(item.id,demo,item.self)
}
const emits = defineEmits(['handleClick'])

const userFavoriteList = computed(()=>userStore.userFavoriteList)
const favoritoGame = ()=>{
    let id = props.gameInfo.id
    if (userStore.isLogin) {
        if(userFavoriteList.value.includes(id.toString())){
            gameApi.unFavorite({gameId:id}).then(res=>{
                console.log(' userFavoriteList.value', userFavoriteList.value)
                let index = -1
                 userFavoriteList.value.forEach((item,itemIndex)=>{
                    if(item == id.toString()) {
                        index = itemIndex
                        return;
                    }
                })
                console.log(' userFavoriteList.value', index)
                if(index>-1) {
                    userStore.userFavoriteList.splice(index,1)
                    console.log(' userFavoriteList.value', userFavoriteList.value)
                }
                $message.success(t("tipsMessage.success"))
                eventBus.emit('updateLikeList');
            })
        }else{
            gameApi.favorite({gameId:id}).then(res=>{
                userStore.userFavoriteList.push(`${id}`)
                console.log(' userFavoriteList.value', userFavoriteList.value)
                $message.success(t("tipsMessage.success"))
                eventBus.emit('updateLikeList');
            })
        }
    } else {
        configStore.setLoginInfo()
    }
    
}
watch(() => props.gameInfo, (val) => {
    defaultImg.value = $utilsArr.formatOnlineCommonImg(val.icon)
})
const handleError = (v)=>{
    // configStore.baseConfig.gameImageUrl
    defaultImg.value = $utilsArr.formatOnlineCommonImg(configStore.baseConfig.gameImageUrl)
    isError.value = true
}
const handleImageLoad = (v)=>{
    showLodaing.value = false
}
</script>
<style lang="scss" scoped>
.game-item-wrapper{
    .img-box{
        position: relative;
        transition: all .2s;
        width: 100%; /* 图片项宽度填充整个网格单元 */
        padding-bottom: 100%; /* 图片项高度相对于宽度的 1:1 比例，实现占位 */
        overflow: hidden; /* 确保超出部分被隐藏，以防止图片变形 */
        background-size: 100% 100%;
        // background-color: #333944;
        .img-box-style{
            position: absolute;
            top: 0;
            left: 0;
            width: 100%; /* 图片填充整个图片项 */
            height: 100%;
            overflow: hidden;            
            object-fit: fill;  /* 使用 fill 属性填充整个图片项 */
            z-index:2;
        }
        .img-style {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%; /* 图片填充整个图片项 */
            height: 100%;
            border-radius: 40%;
            padding:8.2%;
            object-fit: fill;  /* 使用 fill 属性填充整个图片项 */
            overflow: hidden;
        }
        .loading-img{
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%,-50%);
            width: 40px; /* 图片填充整个图片项 */
            height: 52px;
            padding:0;
            object-fit:scale-down; /* 使用 fill 属性填充整个图片项 */
            z-index:1;
            border-radius: 0px;
        }
        &:hover{
            .img-hover{
                opacity:1;
            }
        }

    }
    .name{
        height: 33px;
        padding: 10px 0 1px;
        display:flex;
        flex-direction:column;
        background-size: 100% 100%;
        span{
            margin:0 auto;
            text-align:center;
            font-size: 10px;
            font-family:"Inter-Medium";
            color: #FFFFFF;
            line-height: 12px;
            text-shadow: 0px 1px 1px #000000;
            // display: -webkit-box;
            // -webkit-line-clamp: 1;
            // -webkit-box-orient: vertical;
            display: inline-block;
            width: 91px;
            overflow: hidden;
            white-space: nowrap;
            text-overflow: ellipsis;
        }
    }
}

.img-hover{
    align-items:center;
    // -webkit-backdrop-filter: blur(3px);
    backdrop-filter: blur(3px);
    background-color:rgba(0,0,0,0.6);
    bottom: 0;
    display: flex;
    justify-content: center;
    left: 0;
    opacity: 0;
    padding: 10px;
    position: absolute;
    right: 0;
    top: 0;
    -webkit-transform: translateZ(1px);
    transform: translateZ(1px);
    transition: opacity .1s ease-in-out;
    z-index: 2;
    cursor: pointer;
    border-radius: 48px;
    flex-direction:column;
    &.img-like{
        transition:none;
        background-color:rgba(0, 0, 0, 0);
        // background-color:#333944;
        opacity:1;
        backdrop-filter: none;
    }
    p{
        color: #fff;
        font-weight: 600;
        letter-spacing: -.02em;
        text-align: center;
        word-break: break-word;
    }
    img{
        height:54px;
        width:54px;
    }
    .demo-button{
        width:74px;
        height:24px;
        background-repeat: no-repeat;
        background-size:74px 24px;
        text-align:center;
        font-size:11px;
        line-height:24px;
        font-weight: bold;
        color: #FFF0BB;
        margin-top:15px;
    }
    .like-img{
        width:24px;
        height:24px;
        position:absolute;
        top:17%;
        right:17%;
    }
    .like-img-click-container{
        width:24px;
        height:24px;
        position:absolute;
        top:17%;
        right:17%;
        .like-img-click{
            position:absolute;
            width: 12px;
            height: 12px;
            left: 50%;
            top: 50%;
            transform: translate(-50%, -50%);
        }   
    }
    
}

::v-deep(.n-image img){
    width: 100%;
    height: 100%;
    position:absolute;
    top:0;
    left:0;
}
.img-placeholder{
    width: 100%;
    height: 100%;
    border-radius: 5px;
    background: #16202D;
}
@media screen and (min-width: 768px){

    .game-item-wrapper{
        .img-box{
        }
        .name{
            height: 56px;
            padding: 16px 0 26px;
            span{
                margin:0 auto;
                text-align:center;
                font-size: 12px;
                color: #FFFFFF;
                line-height: 14px;
                text-shadow: 0px 1px 1px #000000;
                display: -webkit-box;
                -webkit-line-clamp: 2;
                -webkit-box-orient: vertical;
                overflow: hidden;

            }
        }
    }    

}
</style>    