<template>
    <div class="third-game-top"  >
        <div class="game-top-item">
            <div>{{gameInfo.gameName}}</div>
            <div style="margin-left:12px"><n-icon :component="UserOutlined" size="16" style="margin-right:5px"></n-icon>{{playNum}}</div>
        </div>
        <div class="game-top-item">
            <div @click="favoritoGame">
                <n-icon :component="Heart32Regular" size="16" v-if="!gameInfo.favorite" ></n-icon>
                <n-icon :component="Heart48Filled" color="#FF7892"  v-else size="16" ></n-icon>
                <span class="favor-count" v-if="!configStore.isMobile" :style="{color: gameInfo.favorite ? '#FF7892' : '#fff'}">{{randomNumber}}  {{ $t('gameI18.topInfo.topInfoPanelFavorito')}} </span>
            </div>
            <div class="game-screen">
                <n-icon :component="FullScreenMaximize24Filled" size="16"  v-if="!isScreen" @click="updateIsScreen(true)"></n-icon>
                <n-icon :component="FullScreenMinimize24Filled" size="16"  v-else @click="updateIsScreen(fasle)"></n-icon>
            </div>
        </div>
    </div>
</template>
<script setup name="ThirdGameTopComponent">
import {UserOutlined} from "@vicons/antd"
import { Heart32Regular,Heart48Filled,FullScreenMaximize24Filled,FullScreenMinimize24Filled } from '@vicons/fluent'
import { useConfigStore } from '@/pinia/modules/config'
import { favorite,unFavorite} from '@/api/game'
import { useI18n } from 'vue-i18n'
const { t } = useI18n()
const configStore = useConfigStore()
const props = defineProps({
    gameInfo: {
      type: Object,
      default: () => {},
    },
    isScreen:{
        type: Boolean,
        default: false
    }
})
const emits = defineEmits("update:isScreen","updateFavorite")
const randomNumber = ref(Math.floor(Math.random() * (2000 - 1000 + 1)) + 1000);
const playNum = ref(Math.floor(Math.random() * (1000 - 500 + 1)) + 500);
const favoritoGame = ()=>{
    if(props.gameInfo.favorite){
        unFavorite({gameId:props.gameInfo.gameId}).then(res=>{
            // gameInfo.value.favorite = !gameInfo.value.favorite
            emits('updateFavorite')
            $message.success(t("tipsMessage.success"))
            randomNumber.value --
        })
    }else{
        favorite({gameId:props.gameInfo.gameId}).then(res=>{
            // gameInfo.value.favorite = !gameInfo.value.favorite
            emits('updateFavorite')
            $message.success(t("tipsMessage.success"))
            randomNumber.value ++ 
        })
    }
}


const updateIsScreen = (value)=>{
    emits('update:isScreen',value)
}
</script>
<style lang="scss" scoped>

.third-game-top{
    display: flex;
    justify-content: space-between;
    .game-top-item{
        display: flex;
        div{
            border-radius:6px;
            background:#343434;
            padding: 7px 15px;
            font-size:14px;
            color:#FFF;
            display: flex;
            align-items:center;
        }
    }
}
.favor-count{
    margin-left:6px;
    cursor: pointer;
}
.game-screen{
    padding:7px !important;
    margin-left:12px;
    cursor: pointer;
}
</style>